import React, { useState, useEffect, useRef, useMemo } from 'react';
import { createRoot } from 'react-dom/client';
import { Canvas, useFrame } from '@react-three/fiber';
import { OrthographicCamera, Text } from '@react-three/drei';
import * as THREE from 'three';
import { io } from 'socket.io-client';

import { init as initGameLogic, generateWorld, getTile, destroyTile, canMoveTo, TILE_SIZE, world } from './game';
import { initInput } from './input';
import { Players, RoomInfo, Movement, Player, TileType, WorldMap } from './types';

// --- 3D Components ---

const SCALE = 1 / TILE_SIZE; // Scale from game pixel coordinates to 3D world units

// FIX: Properly typed component props to handle React's special 'key' prop and improve type safety.
interface GrassProps {
    position: [number, number, number];
}
const Grass: React.FC<GrassProps> = ({ position }) => (
    <mesh position={position} rotation={[-Math.PI / 2, 0, 0]}>
        <planeGeometry args={[1, 1]} />
        <meshLambertMaterial color="#7CFC00" />
    </mesh>
);

// FIX: Properly typed component props to handle React's special 'key' prop and improve type safety.
interface ClickableProps {
    position: [number, number, number];
    onClick: () => void;
}
const Stone: React.FC<ClickableProps> = ({ position, onClick }) => (
    <mesh position={position} onClick={onClick}>
        <boxGeometry args={[1, 1, 1]} />
        <meshLambertMaterial color="#a1a1aa" />
    </mesh>
);

// FIX: Properly typed component props to handle React's special 'key' prop and improve type safety.
const Tree: React.FC<ClickableProps> = ({ position, onClick }) => (
    <group position={position} onClick={onClick}>
        {/* Ствол */}
        <mesh position={[0, 0.5, 0]}>
            <cylinderGeometry args={[0.1, 0.1, 1, 8]} />
            <meshLambertMaterial color="#8B4513" />
        </mesh>
        {/* Крона */}
        <mesh position={[0, 1.5, 0]}>
            <sphereGeometry args={[0.7, 8, 8]} />
            <meshLambertMaterial color="#006400" />
        </mesh>
    </group>
);

// FIX: Properly typed component props to handle React's special 'key' prop and improve type safety.
interface Player3DProps {
    player: Player;
}
const Player3D: React.FC<Player3DProps> = ({ player }) => {
    const ref = useRef<THREE.Group>(null!);
    // Плавно интерполируем позицию для гладкого движения
    useFrame(() => {
        if (ref.current) {
            const targetPosition = new THREE.Vector3(player.x * SCALE, 0.5, player.y * SCALE);
            ref.current.position.lerp(targetPosition, 0.1);
        }
    });

    return (
        <group ref={ref}>
            <mesh>
                <capsuleGeometry args={[20 * SCALE, 20 * SCALE, 16, 8]} />
                <meshLambertMaterial color={player.color} />
            </mesh>
            <Text
                position={[0, 1.2, 0]}
                color="white"
                fontSize={0.3}
                anchorX="center"
                anchorY="middle"
                outlineWidth={0.02}
                outlineColor="black"
            >
                {player.nickname}
            </Text>
        </group>
    );
};

const WorldTiles = ({ worldData, onTileClick }) => {
    // Memoize tiles to avoid recalculating on every render
    const tiles = useMemo(() => {
        const tileElements = [];
        for (const key in worldData) {
            const [x, y] = key.split(',').map(Number);
            const type = worldData[key];
            const position: [number, number, number] = [x, 0, y];

            if (type === 'grass') {
                 tileElements.push(<Grass key={key} position={position} />);
            } else if (type === 'stone') {
                position[1] = 0.5; // поднять куб
                tileElements.push(<Stone key={key} position={position} onClick={() => onTileClick(x, y, 'stone')} />);
            } else if (type === 'tree') {
                tileElements.push(<Tree key={key} position={position} onClick={() => onTileClick(x, y, 'tree')} />);
            }
        }
        return tileElements;
    }, [worldData, onTileClick]);

    return <>{tiles}</>;
};

function CameraController({ player }) {
    useFrame(({ camera, clock }) => {
        if (player) {
            const playerPosition = new THREE.Vector3(player.x * SCALE, 0, player.y * SCALE);
            const targetCameraPosition = new THREE.Vector3(playerPosition.x, 10, playerPosition.z + 10);

            // Плавное следование камеры
            camera.position.lerp(targetCameraPosition, 0.05);
            camera.lookAt(playerPosition);
        }
    });
    return null;
}

// Logic component to handle updates inside the Canvas context
const GameLoop = ({ players, myId, isOffline, movement, socket }) => {
    const me = players[myId];

    useFrame(() => {
        if (!me) return;

        const SPEED = 5;
        const PLAYER_RADIUS = 20;

        if (isOffline) {
            let dx = 0;
            let dy = 0;
            if (movement.up) dy -= SPEED;
            if (movement.down) dy += SPEED;
            if (movement.left) dx -= SPEED;
            if (movement.right) dx += SPEED;

            if (canMoveTo(me.x + dx, me.y + dy, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) {
                me.x += dx;
                me.y += dy;
            }
        } else {
            const filteredMovement = { ...movement };
            if (filteredMovement.up && !canMoveTo(me.x, me.y - SPEED, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.up = false;
            if (filteredMovement.down && !canMoveTo(me.x + SPEED, me.y, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.down = false;
            if (filteredMovement.left && !canMoveTo(me.x - SPEED, me.y, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.left = false;
            if (filteredMovement.right && !canMoveTo(me.x + SPEED, me.y, PLAYER_RADIUS * 2, PLAYER_RADIUS * 2)) filteredMovement.right = false;
            socket?.emit('movement', filteredMovement);
        }
    });
    return null;
}

// --- Main Game Scene ---

// Fix: Add explicit prop types to ensure type safety and correct type inference for child components.
const GameScene = ({ players, myId, localInventory, socket, isOffline, movement }: { players: Players, myId: string, localInventory: any, socket: any, isOffline: boolean, movement: Movement }) => {
    const [worldData, setWorldData] = useState<WorldMap>({});
    const me = players[myId];

    useEffect(() => {
        // Генерируем мир один раз при входе в игру
        generateWorld(me.x, me.y);
        setWorldData({ ...world });
    }, []);

    const handleTileClick = (x, y, type) => {
        const playerTileX = Math.floor(me.x / TILE_SIZE);
        const playerTileY = Math.floor(me.y / TILE_SIZE);
        const distance = Math.sqrt(Math.pow(playerTileX - x, 2) + Math.pow(playerTileY - y, 2));

        if (distance > 1.5) return;

        destroyTile(x, y);
        if (type === 'tree') localInventory.wood++;
        if (type === 'stone') localInventory.stone++;

        // Обновляем состояние, чтобы React перерисовал мир
        setWorldData({ ...world });
    };

    return (
        <>
            <div className="hud">
                <div className="inventory-ui">
                    <div>Камень: {localInventory.stone}</div>
                    <div>Дерево: {localInventory.wood}</div>
                </div>
            </div>
            <Canvas>
                <OrthographicCamera makeDefault zoom={50} position={[0, 20, 20]} />
                <ambientLight intensity={0.6} />
                <directionalLight position={[10, 15, 5]} intensity={1.5} castShadow />

                <WorldTiles worldData={worldData} onTileClick={handleTileClick} />
                {Object.values(players).map(p => (
                    <Player3D key={p.id} player={p} />
                ))}

                <CameraController player={players[myId]} />
                <GameLoop players={players} myId={myId} isOffline={isOffline} movement={movement} socket={socket} />
            </Canvas>
        </>
    );
};

// --- App Component ---

function App() {
    const [gameState, setGameState] = useState<'lobby' | 'game'>('lobby');
    const [players, setPlayers] = useState<Players>({});
    const [localPlayerId, setLocalPlayerId] = useState('offline-player');
    const [isOffline, setIsOffline] = useState(false);

    const socketRef = useRef<any>(null);
    const inventoryRef = useRef({ stone: 0, wood: 0 });
    const movementRef = useRef(initInput());
    const nicknameRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        // --- Socket Connection ---
        const socket = io("https://rgp-game.onrender.com");
        socketRef.current = socket;

        socket.on('connect', () => {
            console.log('Connected with ID:', socket.id);
            setLocalPlayerId(socket.id);
        });

        socket.on('gameStart', (initialPlayers) => {
            setPlayers(initialPlayers);
            setIsOffline(false);
            setGameState('game');
        });

        socket.on('state', (serverPlayers) => {
            setPlayers(serverPlayers);
        });

        socket.on('error', (message) => alert(`Ошибка: ${message}`));

        return () => {
            socket.disconnect();
        };
    }, []);

    // --- Handlers ---
    const handleCreateRoom = () => {
        const nickname = nicknameRef.current?.value.trim();
        if (nickname) {
            socketRef.current?.emit('createRoom', 'Новая комната', nickname);
        }
    };

    const handleStartOffline = () => {
        const nickname = nicknameRef.current?.value.trim() || "Player";
        const player: Player = {
            id: 'offline-player',
            x: 400, y: 300,
            color: `hsl(${Math.random() * 360}, 70%, 50%)`,
            nickname: nickname,
            inventory: { stone: 0, wood: 0 }
        };
        setPlayers({ [player.id]: player });
        setLocalPlayerId(player.id);
        setIsOffline(true);
        setGameState('game');
    };

    if (gameState === 'lobby') {
        // Простой UI для лобби, т.к. Tailwind CSS из HTML больше не работает напрямую
        return (
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%' }}>
                <h1>Лобби</h1>
                <input ref={nicknameRef} type="text" placeholder="Ваш никнейм" style={{ padding: '10px', margin: '10px', width: '200px' }} />
                <button onClick={handleCreateRoom} style={{ padding: '10px 20px', margin: '5px' }}>Создать комнату (Онлайн)</button>
                <button onClick={handleStartOffline} style={{ padding: '10px 20px', margin: '5px' }}>Оффлайн игра</button>
            </div>
        );
    }

    return (
        <GameScene 
            players={players} 
            myId={localPlayerId} 
            localInventory={inventoryRef.current} 
            socket={socketRef.current}
            isOffline={isOffline}
            movement={movementRef.current}
        />
    );
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

