    );
};

const WorldTiles = ({ worldData, onTileClick }) => {
    // Memoize tiles to avoid recalculating on every render
    const tiles = useMemo(() => {
        const tileElements = [];
        for (const key in worldData) {
            const [x, y] = key.split(',').map(Number);
            const type = worldData[key];
            const position: [number, number, number] = [x, 0, y];

            if (type === 'grass') {
                 tileElements.push(<Grass key={key} position={position} />);
            } else if (type === 'stone') {
                position[1] = 0.5; // поднять куб
                tileElements.push(<Stone key={key} position={position} onClick={() => onTileClick(x, y, 'stone')} />);
            } else if (type === 'tree') {
                tileElements.push(<Tree key={key} position={position} onClick={() => onTileClick(x, y, 'tree')} />);
