                <directionalLight position={[10, 15, 5]} intensity={1.5} castShadow />

                <WorldTiles worldData={worldData} onTileClick={handleTileClick} />
                {Object.values(players).map(p => (
                    <Player3D key={p.id} player={p} />
                ))}

                <CameraController player={players[myId]} />
                <GameLoop players={players} myId={myId} isOffline={isOffline} movement={movement} socket={socket} />
            </Canvas>
        </>
    );
};

